import{_ as a,o as r,c as d,ag as e}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.BQrd_3-w.jpg",l="/kaiping-reports/assets/2.BTdYdlia.jpg",i="/kaiping-reports/assets/3.BBO620Hw.jpg",b=JSON.parse('{"title":"从风貌保存到建造智慧传承：开平碉楼遗产保护的范式转换","description":"","frontmatter":{"title":"从风貌保存到建造智慧传承：开平碉楼遗产保护的范式转换"},"headers":[],"relativePath":"reports/王淑珍/王淑珍_调研报告.md","filePath":"reports/王淑珍/王淑珍_调研报告.md"}'),u={name:"reports/王淑珍/王淑珍_调研报告.md"};function q(h,t,n,s,p,c){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="从风貌保存到建造智慧传承-开平碉楼遗产保护的范式转换" tabindex="-1">从风貌保存到建造智慧传承：开平碉楼遗产保护的范式转换 <a class="header-anchor" href="#从风貌保存到建造智慧传承-开平碉楼遗产保护的范式转换" aria-label="Permalink to &quot;从风貌保存到建造智慧传承：开平碉楼遗产保护的范式转换&quot;">​</a></h1><p>——基于&quot;保护底线&quot;的实证研究与批判反思</p><p><strong>考察地点：</strong> 广东省江门市开平市</p><p><strong>考察时间：</strong> 2026年3月31日</p><p><strong>考察人：</strong> 王淑珍</p><p><strong>指导教师：</strong> 石拓 教授</p><p><img src="'+o+'" alt="图1：赤坎古镇古建区街景实拍"></p><h2 id="一、引言-深入了解-碉楼-遗产保护与研究现状-定位研究缺口" tabindex="-1">一、引言：深入了解&quot;碉楼&quot;遗产保护与研究现状，定位研究缺口 <a class="header-anchor" href="#一、引言-深入了解-碉楼-遗产保护与研究现状-定位研究缺口" aria-label="Permalink to &quot;一、引言：深入了解&quot;碉楼&quot;遗产保护与研究现状，定位研究缺口&quot;">​</a></h2><p>开平碉楼作为世界文化遗产，其核心价值不仅在于中西合璧的视觉形式，更深藏于材料选择、建造工艺背后的文化逻辑与技术智慧。然而，现有研究多聚焦于保护模式的表面对比（立园vs仓东村vs赤坎古镇的优劣评判），却缺乏统一的评判标尺与可操作的诊断工具，导致讨论陷入&quot;价值先行&quot;的争议；同时，对碉楼作为&quot;建造行为产物&quot;的本质属性关注不足，材料、工艺与文化价值的关联机制尚未得到系统阐释。</p><p>本文以立园（博物馆式保护）、仓东村（社区活态保护）、赤坎古镇（文旅开发保护）为典型案例，建立材料（materiality）—构造（tectonics）—细部（detail）—空间干预（spatial intervention）四维技术框架，以原真性、可识别、可持续性三项保护底线为评判标尺，探讨遗产保护从&quot;风貌保存&quot;走向&quot;智慧传承&quot;的范式转换路径。研究试图填补&quot;工具缺失&quot;与&quot;机制不明&quot;的双重缺口，为乡土遗产保护提供可迁移的方法论参考。</p><h2 id="二、案例分析-三个案例在四维框架下的现状诊断与趋势预警" tabindex="-1">二、案例分析：三个案例在四维框架下的现状诊断与趋势预警 <a class="header-anchor" href="#二、案例分析-三个案例在四维框架下的现状诊断与趋势预警" aria-label="Permalink to &quot;二、案例分析：三个案例在四维框架下的现状诊断与趋势预警&quot;">​</a></h2><h3 id="_2-1-立园-高保真与低活力的悖论" tabindex="-1">2.1 立园：高保真与低活力的悖论 <a class="header-anchor" href="#_2-1-立园-高保真与低活力的悖论" aria-label="Permalink to &quot;2.1 立园：高保真与低活力的悖论&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>现状</th><th>底线评判</th><th>趋势预警</th></tr></thead><tbody><tr><td>材料</td><td>青砖、彩砖、老式玻璃严格保留，修复遵循最小干预</td><td>✅原真性</td><td>风化加速，需预防性保护介入</td></tr><tr><td>构造</td><td>钢筋混凝土框架+青砖外皮完整保留，隐蔽式钢构加固</td><td>✅可持续性</td><td>隐蔽加固依赖外部技术，本土技艺传承断档</td></tr><tr><td>细部</td><td>花砖纹理清晰，柱头雕花中西融合，玻璃光影效果独特</td><td>✅原真性</td><td>修复技术档案缺失，再干预风险累积</td></tr><tr><td>空间干预</td><td>环形单向参观动线取代原有递进序列，空间活力受限</td><td>⚠️可持续性</td><td>静态化持续，活态传承机制未建立</td></tr></tbody></table><p>立园实现&quot;博物馆级&quot;保存，但建筑被冻结为历史标本，例如图4呈现的立园泮立楼顶楼的几句传统色彩的室内设施，园区古建活化改造的时候没有抓住这个传统氛围浓厚的区域详细展示和介绍，没有乘机讨论和延伸谢氏留洋和华侨的身份与传统元素的关系。公众以&quot;观看者&quot;而非&quot;使用者&quot;进入，建造智慧停留在&quot;被动保护&quot;层面。</p><p><img src="'+l+'" alt="图2：立园泮文楼柱头细节图"><img src="'+i+'" alt="图3：立园泮立楼外立面材料示意图"></p><h3 id="_2-2-仓东村-高活力与低规范的失衡" tabindex="-1">2.2 仓东村：高活力与低规范的失衡 <a class="header-anchor" href="#_2-2-仓东村-高活力与低规范的失衡" aria-label="Permalink to &quot;2.2 仓东村：高活力与低规范的失衡&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>现状</th><th>底线评判</th><th>趋势预警</th></tr></thead><tbody><tr><td>材料</td><td>乡土材料就地取材，但部分存在随意替换花砖、现代材料替代传统材料</td><td>❌原真性</td><td>代际更替中，传统材料认知持续流失</td></tr><tr><td>构造</td><td>传统砌筑工艺实用简洁，但构造加固不到位，谢氏祖宅改造时存在随意修改梁架支撑的情况</td><td>⚠️可持续性</td><td>自主修缮技术退化，结构性损伤累积</td></tr><tr><td>细部</td><td>传统纹样保留，但简化工艺、破损未及时修复</td><td>❌原真性</td><td>工艺细节加速消失，&quot;修旧如新&quot;趋势明显</td></tr><tr><td>空间干预</td><td>院落适度改造满足现代生活，但部分改造扰动装饰与空间协调性</td><td>⚠️可识别</td><td>现代功能需求与传统空间矛盾加剧</td></tr></tbody></table><p>仓东村实现遗产与日常生活的真实融合，但保护依赖村民经验而非专业指导，建造智慧在&quot;自然损耗&quot;中无序流失。</p><h3 id="_2-3-赤坎古镇-高传播与低原真的冲突" tabindex="-1">2.3 赤坎古镇：高传播与低原真的冲突 <a class="header-anchor" href="#_2-3-赤坎古镇-高传播与低原真的冲突" aria-label="Permalink to &quot;2.3 赤坎古镇：高传播与低原真的冲突&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>现状</th><th>底线评判</th><th>趋势预警</th></tr></thead><tbody><tr><td>材料</td><td>现代仿传统材料为主，新旧界限模糊复刻重构取代原始工艺</td><td>❌原真性 ❌可识别</td><td>新材料老化速度与旧构差异将显现，二次损伤风险高</td></tr><tr><td>构造</td><td>简化砌筑流程，结构改造适配商业空间，扰动原有结构逻辑</td><td>⚠️可持续性</td><td>商业空间迭代快，结构反复改造将加剧损耗</td></tr><tr><td>细部</td><td>装饰统一化、商业化修饰，原有工艺细节未能充分保留</td><td>❌原真性</td><td>景观化审美固化，真实历史信息持续弱化</td></tr><tr><td>空间干预</td><td>街道重塑、业态布局强度最大，夜景灯光等现代设施植入明显</td><td>⚠️可持续性</td><td>过度商业化挤压原生生活空间，&quot;表演性&quot;替代&quot;真实性&quot;</td></tr></tbody></table><p>赤坎古镇实现碉楼文化的高强度传播，但从严格遗产保护视角审视，建造智慧沦为商业装饰附属，建筑从&quot;历史信息载体&quot;退化为&quot;怀旧想象投射&quot;。</p><h2 id="三、理论视角-双重支撑与底线依据" tabindex="-1">三、理论视角：双重支撑与底线依据 <a class="header-anchor" href="#三、理论视角-双重支撑与底线依据" aria-label="Permalink to &quot;三、理论视角：双重支撑与底线依据&quot;">​</a></h2><p><img src="'+o+'" alt="图11：立园牌坊实拍图（留存保护效果较好）"></p><h3 id="_3-1-建筑史视角-近代技术转型的-连续剖面" tabindex="-1">3.1 建筑史视角：近代技术转型的&quot;连续剖面&quot; <a class="header-anchor" href="#_3-1-建筑史视角-近代技术转型的-连续剖面" aria-label="Permalink to &quot;3.1 建筑史视角：近代技术转型的&quot;连续剖面&quot;&quot;">​</a></h3><p>立园的&quot;钢筋混凝土框架+青砖外皮&quot;反映华侨对现代结构的拥抱与传统符号的依赖；仓东村的&quot;红砖墙体+进口水泥瓦&quot;体现普通华侨的技术实用主义；赤坎骑楼的&quot;功能主义装饰&quot;记录Art Deco风格在侨乡的影响。三处案例共同构成近代中国建筑转型的实物证据，但赤坎古镇的商业化重构切断了这一历史信息的完整性。</p><h3 id="_3-2-保护理论视角-三项底线的学理基础" tabindex="-1">3.2 保护理论视角：三项底线的学理基础 <a class="header-anchor" href="#_3-2-保护理论视角-三项底线的学理基础" aria-label="Permalink to &quot;3.2 保护理论视角：三项底线的学理基础&quot;">​</a></h3><ul><li><strong>&quot;原真性&quot;</strong> 对应《威尼斯宪章》真实性原则，要求材料、工艺、设计的完整保留</li><li><strong>&quot;可识别&quot;</strong> 对应《奈良文件》可识别性原则，要求修复部分与历史原构视觉区分</li><li><strong>&quot;可持续性&quot;</strong> 综合《中国文物古迹保护准则》稳定性要求与ICOMOS可持续性议题，兼顾遗产安全、使用需求与长期留存</li></ul><h2 id="四、批判性反思-本质矛盾、伦理维度与反身性" tabindex="-1">四、批判性反思：本质矛盾、伦理维度与反身性 <a class="header-anchor" href="#四、批判性反思-本质矛盾、伦理维度与反身性" aria-label="Permalink to &quot;四、批判性反思：本质矛盾、伦理维度与反身性&quot;">​</a></h2><h3 id="_4-1-三种保护理念的范式偏差" tabindex="-1">4.1 三种保护理念的范式偏差 <a class="header-anchor" href="#_4-1-三种保护理念的范式偏差" aria-label="Permalink to &quot;4.1 三种保护理念的范式偏差&quot;">​</a></h3><ul><li><strong>立园</strong>：&quot;标本化&quot;范式，将遗产保护简化为外观冻结，忽视建造智慧的活态延续</li><li><strong>仓东村</strong>：&quot;经验化&quot;范式，以自然维护取代科学保护，缺乏规范性导致智慧流失</li><li><strong>赤坎古镇</strong>：&quot;景观化&quot;范式，以商业重构牺牲原真信息，建造智慧退化为视觉符号</li></ul><p>三种偏差共同指向核心问题：对&quot;材料—工艺—文化&quot;关联机制的认知不足，遗产保护停留在&quot;物的保存&quot;而非&quot;智慧的传承&quot;。</p><h3 id="_4-2-伦理维度-话语权的分配正义" tabindex="-1">4.2 伦理维度：话语权的分配正义 <a class="header-anchor" href="#_4-2-伦理维度-话语权的分配正义" aria-label="Permalink to &quot;4.2 伦理维度：话语权的分配正义&quot;">​</a></h3><p>遗产保护实践本质上是&quot;谁有权决定遗产命运&quot;的伦理问题：</p><ul><li><strong>立园</strong>的博物馆化意味着专家掌握决策权，这种&quot;专业霸权&quot;可能忽视遗产与使用者的真实联系</li><li><strong>仓东村</strong>的社区参与将决策权交还居民，但社区内部代际认知差异缺乏调和机制</li><li><strong>赤坎古镇</strong>的整体改造则是资本与权力的合谋，居民利益被边缘化</li></ul><p>三种模式对应三种伦理立场，提示我们：遗产保护的终极目标不是&quot;保存&quot;过去的建筑，而是&quot;激活&quot;其当代意义，但这一过程必须建立专家—社区—政府的三方协商机制。</p><h3 id="_4-3-研究框架的局限与开放" tabindex="-1">4.3 研究框架的局限与开放 <a class="header-anchor" href="#_4-3-研究框架的局限与开放" aria-label="Permalink to &quot;4.3 研究框架的局限与开放&quot;">​</a></h3><p>本文提出的四维框架与三项底线，本质上是一种简化模型，用于诊断而非穷尽遗产保护的复杂性。例如，&quot;可持续性&quot;底线在不同气候区、不同遗产类型中的权重可能差异显著；社区参与的&quot;度&quot;也难以量化。本框架的价值在于提供对话起点，而非终极答案——遗产保护的实践智慧，最终仍需在具体情境中协商生成。</p><h2 id="五、优化路径-构建动态平衡机制" tabindex="-1">五、优化路径：构建动态平衡机制 <a class="header-anchor" href="#五、优化路径-构建动态平衡机制" aria-label="Permalink to &quot;五、优化路径：构建动态平衡机制&quot;">​</a></h2><h3 id="_5-1-分级保护标准" tabindex="-1">5.1 分级保护标准 <a class="header-anchor" href="#_5-1-分级保护标准" aria-label="Permalink to &quot;5.1 分级保护标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>核心底线</th><th>活态策略</th></tr></thead><tbody><tr><td>高等级遗产（立园）</td><td>原真性优先</td><td>有限度活态利用，建立技艺传承档案，预防性保护介入</td></tr><tr><td>活态村落（仓东村）</td><td>风貌完整性+规范提升</td><td>专业指导下的自主修缮，代际对话机制，传统材料认知教育</td></tr><tr><td>历史街区（赤坎古镇）</td><td>底线约束下的可持续性</td><td>严格限制空间干预强度，区分&quot;展示空间&quot;与&quot;生活空间&quot;，保留原生生活气息</td></tr></tbody></table><h3 id="_5-2-四维技术策略" tabindex="-1">5.2 四维技术策略 <a class="header-anchor" href="#_5-2-四维技术策略" aria-label="Permalink to &quot;5.2 四维技术策略&quot;">​</a></h3><ul><li><strong>材料</strong>：可识别、可兼容、可逆，新旧质感区分但不冲突，杜绝仿古造假</li><li><strong>构造</strong>：加固补强为主，保留砌筑工艺细节，建立技艺传承档案</li><li><strong>细部</strong>：数字档案与实物档案双轨制，系统记录雕刻、门窗等历史信息</li><li><strong>空间干预</strong>：科学流线组织、功能适度植入、降低人为损耗，支持安全、可持续的活态使用</li></ul><h3 id="_5-3-反向验证-忽视底线的代价" tabindex="-1">5.3 反向验证：忽视底线的代价 <a class="header-anchor" href="#_5-3-反向验证-忽视底线的代价" aria-label="Permalink to &quot;5.3 反向验证：忽视底线的代价&quot;">​</a></h3><p>粤西某碉楼村落（隐去名称）曾因忽视&quot;可识别&quot;底线，2015年采用仿古材料整体翻新，2023年新材料老化速度与旧构差异显著，釉面剥落与基层开裂并存，导致二次损伤与重复干预成本倍增——印证了&quot;可识别、可逆&quot;原则的长远价值。</p><h3 id="_5-4-参与式决策机制" tabindex="-1">5.4 参与式决策机制 <a class="header-anchor" href="#_5-4-参与式决策机制" aria-label="Permalink to &quot;5.4 参与式决策机制&quot;">​</a></h3><p>打破&quot;保护—利用—传承&quot;对立的困境，建立三方协同：</p><ul><li><strong>专家</strong>：提供技术规范与底线标准，建立技艺档案库，避免&quot;专业霸权&quot;</li><li><strong>社区</strong>：参与日常维护与活态传承，建立代际对话机制，调和功能需求与情感记忆</li><li><strong>政府/资本</strong>：接受底线约束与公众监督，限制商业开发强度，保障居民参与权</li></ul><h2 id="六、结论-范式转换与未来方向" tabindex="-1">六、结论：范式转换与未来方向 <a class="header-anchor" href="#六、结论-范式转换与未来方向" aria-label="Permalink to &quot;六、结论：范式转换与未来方向&quot;">​</a></h2><p>本文通过四维框架与三项底线的建立，完成了从现象到本质的研究。核心观点在于：遗产保护正经历从&quot;风貌保存&quot;到&quot;智慧传承&quot;的范式转换——其本质不是保存&quot;物的躯壳&quot;，而是延续&quot;做的智慧&quot;，实现材料原真性、工艺完整性、文化延续性的统一。</p><p>开平碉楼的材料表达与建造智慧，是近代中西建筑文化对话的具象体现。唯有坚守保护底线、强化专业支撑、建立参与式决策机制，才能让建造智慧从&quot;被动保存&quot;走向&quot;活态传承&quot;，从&quot;历史标本&quot;回归&quot;生活空间&quot;。</p><p>未来研究可进一步追踪：数字技术（如BIM+GIS）能否提升建造智慧档案化的精度与可及性？气候适应性改造如何纳入&quot;可持续性&quot;底线的评估体系？这些问题将决定本文框架的迭代方向，也邀请学界共同推进乡土遗产保护的方法论创新。</p><h2 id="六、附录-调研记录" tabindex="-1">六、附录：调研记录 <a class="header-anchor" href="#六、附录-调研记录" aria-label="Permalink to &quot;六、附录：调研记录&quot;">​</a></h2><h3 id="_6-1-摄影记录" tabindex="-1">6.1 摄影记录 <a class="header-anchor" href="#_6-1-摄影记录" aria-label="Permalink to &quot;6.1 摄影记录&quot;">​</a></h3><p>本报告共插入11张现场照片，分别展示：</p><ul><li>图1：赤坎古镇街景实拍</li><li>图2-图4：立园建筑外立面材料与装饰</li><li>图5-图7：仓东村村落景观、民居建筑与结构加固</li><li>图8-图10：赤坎古镇商业化泛滥实拍图</li><li>图11：立园庭院内的牌楼实拍图</li><li>图12-图13：仓东村雕花和花窗细节实拍图</li><li>图14：赤坎古镇沿河古建区实拍图</li><li>图15：立园泮立楼室内图（来源于网络）</li><li>图15：仓东村接客停留区水池改造后实拍图</li><li>图16：赤坎古镇固件实拍图</li><li>图17-图18：无名营造社展出的珍贵碉楼技术性图纸</li></ul><h3 id="_6-2-文献资料" tabindex="-1">6.2 文献资料 <a class="header-anchor" href="#_6-2-文献资料" aria-label="Permalink to &quot;6.2 文献资料&quot;">​</a></h3><p><strong>参考书目：</strong></p><ul><li>《开平碉楼》，广东省文物考古研究所，文物出版社，2007</li><li>《华侨建筑文化研究》，华侨大学建筑学院，中国建筑工业出版社，2010</li><li>《文化遗产保护的理论与实践》，同济大学建筑与城市规划学院，同济大学出版社，2015</li><li>《开平碉楼村落保护与利用研究》，华南理工大学出版社，2018</li></ul><p><strong>报告撰写人：</strong> 王淑珍</p><p><strong>报告完成时间：</strong> 2026年4月19日</p><p><strong>字数统计：</strong> 约4380字</p><p><strong>关键词：</strong> 开平碉楼；遗产保护；建造智慧；保护底线；活态传承；范式转换</p>',62)])])}const g=a(u,[["render",q]]);export{b as __pageData,g as default};
